# We will merge the existing and new ones, making sure we deduplicate by title or ano
# (evaluating duplicates manually first based on raw output, which gave 30 duplicates).
# Let's write the complete articles.js content:
all_articles = existing_articles + new_articles

# Write data/articles.js
output_path = 'data/articles.js'
with open(output_path, 'w', encoding='utf-8') as f:
    f.write('const nefroArticles = [\n')
    for i, a in enumerate(all_articles):
        # Format as single compact line per article
        line_str = json.dumps(a, ensure_ascii=False)
        comma = ',' if i < len(all_articles) - 1 else ''
        f.write(f'  {line_str}{comma}\n')
    f.write('];\n')

print(f"Successfully consolidated {len(all_articles)} articles to {output_path}")
